  ('dietitian-moex-00047', 'dietitian', 'dietitian-moex-114-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '高脂飲食與乳癌相關性的研究報告指出：高脂飲食與非高脂飲食得乳癌者的勝算比為3.5，下列敘 述何者正確？', '["僅能從世代研究獲得此結果", "每日脂肪攝取超過熱量35%者易得乳癌", "高脂飲食者罹患乳癌的風險是非高脂飲食者的3.5倍", "高脂飲食者罹患乳癌的風險比非高脂飲食者高3.5倍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:48+00:00", "source_pdf_sha1": "0bb91fb123c8", "answer_pdf_sha1": "8515a16bbc16", "source_family": "moex-gov-tw", "moex": {"exam_code": "114030", "c": "102", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "114", "exam_name": "114年第一次專技人員高等考試營養師、護理師、社會工作師考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
